import moment from 'moment';
import { db } from '../main'
var moment_tz = require('moment-timezone');

export const reserveService = {
    addReserve: (data) => {
        return new Promise((resolve, reject) => {
            db.collection('reserves').add({
                date: moment(data.date).toISOString(),
                schedule: data.schedule,
                document: data.document,
                name: data.name,
                lastname: data.lastname,
                phone: data.phone,
                email: data.email,
                place: data.place,
                frotisCultivo: data.frotisCultivo,
                created_at: moment_tz().tz("America/Bogota").format(),
                updated_at: moment_tz().tz("America/Bogota").format()
            }).then(rta => {
                resolve(rta);
            }).catch(err => {
                reject(err);
            })
        })
    },
    updateReserve: (data, id) => {
        return new Promise((resolve, reject) => {
            db.collection('reserves').doc(id)
                .update({
                    date: moment(data.date).toISOString(),
                    schedule: data.schedule,
                    document: data.document,
                    name: data.name,
                    lastname: data.lastname,
                    phone: data.phone,
                    email: data.email,
                    place: data.place,
                    frotisCultivo: data.frotisCultivo,
                    updated_at: moment_tz().tz("America/Bogota").format()
                }).then(rta => {
                    resolve(rta);
                }).catch(err => {
                    reject(err);
                })
        })
    },
    updateReserveFrotis: (data, id) => {
        return new Promise((resolve, reject) => {
            db.collection('reserves').doc({ 'document': data.document, 'date': moment(data.date).toISOString(), 'place': data.place })
                .update({
                    date: moment(data.date).toISOString(),
                    schedule: data.schedule,
                    document: data.document,
                    name: data.name,
                    lastname: data.lastname,
                    phone: data.phone,
                    email: data.email,
                    place: data.place,
                    frotisCultivo: data.frotisCultivo
                }).then(rta => {
                    resolve(rta);
                }).catch(err => {
                    reject(err);
                })
        })
    },
    deleteReserve: (id) => {
        return new Promise((resolve, reject) => {
            db.collection('reserves').doc(id)
                .delete().then(rta => {
                    resolve(rta);
                }).catch(err => {
                    reject(err);
                })
        })
    },
    getReservesByDate: (date, place) => {
        return new Promise((resolve, reject) => {
            let dateSearched = moment(date).toISOString()

            db.collection('reserves')
                .where('date', '==', dateSearched)
                .where('place', '==', place)
                .get()
                .then(snap => {
                    let rta = [];
                    snap.forEach(snapHijo => {
                        let item = {
                            id: snapHijo.id,
                            document: snapHijo.data().document,
                            name: snapHijo.data().name + ' ' + snapHijo.data().lastname,
                            lastname: snapHijo.data().lastname,
                            phone: snapHijo.data().phone,
                            email: snapHijo.data().email,
                            date: snapHijo.data().date,
                            schedule: snapHijo.data().schedule,
                            place: snapHijo.data().place,
                            frotisCultivo: snapHijo.data().frotisCultivo
                        };
                        rta.push(item);
                    })

                    resolve(rta);
                })
                .catch(err => {
                    reject(err);
                })
        })
    },
    getUserReservesByDoc: (docUser, place) => {
        return new Promise((resolve, reject) => {
            let today = moment().toISOString()
            db.collection('reserves')
                .where('document', '==', docUser)
                .where('date', '>', today)
                .where('place', '==', place)
                .get()
                .then(snap => {
                    let rta = [];
                    snap.forEach(snapHijo => {
                        let item = {
                            id: snapHijo.id,
                            date: snapHijo.data().date,
                            schedule: snapHijo.data().schedule,
                            place: snapHijo.data().place,
                            frotisCultivo: snapHijo.data().frotisCultivo
                        };
                        rta.push(item);
                    })
                    resolve(rta);
                })
                .catch(err => {
                    reject(err);
                })
        })
    }
}