
import { placeService } from '../../services/PlaceService'

export default {
    namespaced: true,
    state: {
        places: [],
    },
    mutations: {
        setPlaces: (state, payload) => {
            state.places = payload;
        }
    },
    actions: {
        getPlaces: (context) => {
            return new Promise((resolve, reject) => {
                placeService.getPlaces()
                    .then(rta => {
                        context.commit('setPlaces', rta);
                        resolve(true);
                    })
                    .catch(err => {
                        reject(err);
                    })
            })
        }
    },
    getters: {

    }
}