import { db } from '../main'

export const userService = {
    getUserByDoc: (docUser) => {
        return new Promise((resolve, reject) => {
            db.collection('users')
                .where('document', '==', docUser)
                .get()
                .then(snap => {
                    let rta = {};
                    if (snap.empty == true) {
                        resolve(rta);
                    }
                    snap.forEach(snapHijo => {
                        rta = {
                            id: snapHijo.id,
                            document: snapHijo.data().document,
                            name: snapHijo.data().name,
                            lastname: snapHijo.data().lastname,
                            phone: snapHijo.data().phone,
                            email: snapHijo.data().email,
                        };
                    })
                    resolve(rta);
                })
        })
    },
    createUser: (data) => {
        return new Promise((resolve, reject) => {
            db.collection('users').add({
                document: data.document,
                name: data.name,
                lastname: data.lastname,
                phone: data.phone,
                email: data.email,
                survey: data.survey
            }).then(rta => {
                resolve(rta);
            }).catch(err => {
                reject(err)
            })
        })
    },
    updateUser: (idUser, data) => {
        return new Promise((resolve, reject) => {
            db.collection('users').doc(idUser).update({
                document: data.document,
                name: data.name,
                lastname: data.lastname,
                phone: data.phone,
                email: data.email,
                survey: data.survey
            }).then(rta => {
                resolve(rta);
            }).catch(err => {
                reject(err)
            })
        })
    },
    deleteUser: (idUser) => {
        return new Promise((resolve, reject) => {
            db.collection('users').doc(idUser).delete().then(rta => {
                resolve(rta);
            }).catch(err => {
                reject(err)
            })
        })
    }
}