import { db } from '../main'

export const placeService = {
    getPlaces: () => {
        return new Promise((resolve, reject) => {
            let placesLocal = JSON.parse(localStorage.getItem("places-local"));
            if (placesLocal) {
                // console.log('places desde local')
                resolve(placesLocal);
            } else {
                db.collection('places')
                    .orderBy('name', 'asc')
                    .get()
                    .then(snap => {
                        var places = [];
                        snap.forEach(el => {
                            places.push({ id: el.id, ...el.data() })
                        })
                        localStorage.setItem("places-local", JSON.stringify(places));
                        resolve(JSON.parse(localStorage.getItem("places-local")));
                    })
                    .catch(err => {
                        reject(err);
                    })
            }
        });
    }
}